 1→export interface RatingPointLike {
 2→  rating: number;
 3→}
 4→
 5→export interface PlayerProgress {
 6→  estimatedGames: number;
 7→  longestWinStreak: number;
 8→}
 9→
10→export function isMissingProgressColumnError(err: unknown): boolean {
11→  return (
12→    err instanceof Error &&
13→    /no such column: (estimated_games|longest_win_streak)/i.test(err.message)
14→  );
15→}
16→
17→export function computePlayerProgressFromHistory<T extends RatingPointLike>(
18→  history: T[]
19→): PlayerProgress {
20→  let estimatedGames = 0;
21→  let currentWinStreak = 0;
22→  let longestWinStreak = 0;
23→
24→  for (let i = 1; i < history.length; i++) {
25→    const delta = history[i].rating - history[i - 1].rating;
26→
27→    if (delta > 0) {
28→      estimatedGames++;
29→      currentWinStreak++;
30→      if (currentWinStreak > longestWinStreak) {
31→        longestWinStreak = currentWinStreak;
32→      }
33→    } else if (delta < 0) {
34→      estimatedGames++;
35→      currentWinStreak = 0;
36→    }
37→  }
38→
39→  return {
40→    estimatedGames,
41→    longestWinStreak,
42→  };
43→}
