428→async function recomputePlayerProgress(seasonId: number): Promise<void> {
429→  log("Recomputing player progress stats...");
430→
431→  const currentResp = await queryD1<{ account_id: string }>({
432→    sql: `SELECT account_id FROM player_latest WHERE season_id = ?`,
433→    params: [seasonId],
434→  });
435→  const currentRows = currentResp.result[0]?.results ?? [];
436→  if (currentRows.length === 0) {
437→    log("  No current players found, skipping progress recompute.");
438→    return;
439→  }
440→
441→  const progressMap = new Map(
442→    currentRows.map((row) => [
443→      row.account_id,
444→      { estimatedGames: 0, longestWinStreak: 0 },
445→    ])
446→  );
447→
448→  const historyResp = await queryD1<{ account_id: string; rating: number }>({
449→    sql: `SELECT account_id, rating
450→          FROM player_history
451→          WHERE season_id = ?
452→          ORDER BY account_id ASC, snapshot_id ASC`,
453→    params: [seasonId],
454→  });
455→  const historyRows = historyResp.result[0]?.results ?? [];
456→
457→  let currentAccountId: string | null = null;
458→  let currentHistory: Array<{ rating: number }> = [];
459→
460→  const flushCurrentHistory = () => {
461→    if (!currentAccountId || !progressMap.has(currentAccountId)) {
462→      return;
463→    }
464→
465→    progressMap.set(
466→      currentAccountId,
467→      computePlayerProgressFromHistory(currentHistory)
468→    );
469→  };
470→
471→  for (const row of historyRows) {
472→    if (row.account_id !== currentAccountId) {
473→      flushCurrentHistory();
474→      currentAccountId = row.account_id;
475→      currentHistory = [{ rating: row.rating }];
476→      continue;
477→    }
478→
479→    currentHistory.push({ rating: row.rating });
480→  }
481→  flushCurrentHistory();
482→
483→  const progressEntries = Array.from(progressMap.entries());
484→  for (let i = 0; i < progressEntries.length; i += BATCH_SIZE) {
485→    const batch = progressEntries.slice(i, i + BATCH_SIZE);
486→    await queryD1(
487→      batch.map(([accountId, progress]) => ({
488→        sql: `UPDATE player_latest
489→              SET estimated_games = ?, longest_win_streak = ?
490→              WHERE season_id = ? AND account_id = ?`,
491→        params: [
492→          progress.estimatedGames,
493→          progress.longestWinStreak,
494→          seasonId,
495→          accountId,
496→        ],
497→      }))
498→    );
499→  }
500→
501→  log(`  Recomputed progress for ${progressEntries.length} players.`);
502→}
