504→async function syncPlayerTables(
505→  snapshotId: number,
506→  seasonId: number,
507→  fetchedAt: string,
508→  entries: LeaderboardEntry[]
509→): Promise<void> {
510→  log("Syncing player tables...");
511→
512→  // 1. Read current player_latest for this season
513→  const prevResp = await queryD1<PlayerLatestRow>({
514→    sql: `SELECT account_id, username, position, rating FROM player_latest WHERE season_id = ?`,
515→    params: [seasonId],
516→  });
517→  const prevRows = prevResp.result[0]?.results ?? [];
518→  const prevMap = new Map<string, PlayerLatestRow>();
519→  for (const row of prevRows) {
520→    prevMap.set(row.account_id, row);
521→  }
522→
523→  // 2. Find 24h-ago baseline snapshot (or earliest snapshot if season < 24h old)
524→  const baselineResp = await queryD1<{ id: number }>({
525→    sql: `SELECT id FROM snapshots
526→          WHERE season_id = ? AND status = 'ready'
527→            AND total_entries > 1
528→            AND fetched_at <= datetime(?, '-1 day')
529→          ORDER BY fetched_at DESC LIMIT 1`,
530→    params: [seasonId, fetchedAt],
531→  });
532→  let baselineSnapshotId = baselineResp.result[0]?.results[0]?.id ?? null;
533→
534→  // If no 24h-ago snapshot exists (season < 24h old), use the earliest snapshot
535→  if (!baselineSnapshotId) {
536→    const earliestResp = await queryD1<{ id: number }>({
537→      sql: `SELECT id FROM snapshots
538→            WHERE season_id = ? AND status = 'ready'
539→              AND total_entries > 1
540→            ORDER BY fetched_at ASC LIMIT 1`,
541→      params: [seasonId],
542→    });
543→    baselineSnapshotId = earliestResp.result[0]?.results[0]?.id ?? null;
544→  }
545→
546→  // 3. Detect changes and build batches
547→  const changed: LeaderboardEntry[] = [];
548→  const currentAccountIds = new Set<string>();
549→
550→  for (const entry of entries) {
551→    currentAccountIds.add(entry.AccountId);
552→    const prev = prevMap.get(entry.AccountId);
553→    if (
554→      !prev ||
555→      prev.rating !== entry.Rating ||
556→      prev.position !== entry.Position ||
557→      prev.username !== entry.Username
558→    ) {
559→      changed.push(entry);
560→    }
561→  }
562→
563→  log(`  ${changed.length} changed/new out of ${entries.length} total`);
564→
565→  // 4. Batch INSERT changed rows to player_history
566→  if (changed.length > 0) {
567→    for (let i = 0; i < changed.length; i += BATCH_SIZE) {
568→      const batch = changed.slice(i, i + BATCH_SIZE);
569→      const values = batch
570→        .map(
571→          (e) =>
572→            `(${seasonId}, '${sqlEscape(e.AccountId)}', ${snapshotId}, '${sqlEscape(e.Username)}', ${e.Position}, ${e.Rating})`
573→        )
574→        .join(", ");
575→
576→      await queryD1({
577→        sql: `INSERT OR IGNORE INTO player_history (season_id, account_id, snapshot_id, username, position, rating) VALUES ${values}`,
578→      });
579→    }
580→    log(`  Inserted ${changed.length} rows to player_history`);
581→  }
582→
583→  // 5. Compute 24h baselines for ALL players and UPSERT/UPDATE player_latest
584→  // Build baseline map for ALL players (not just changed ones)
585→  const deltaMap = new Map<string, { position: number; rating: number }>();
586→
587→  if (baselineSnapshotId) {
588→    // Query baselines from player_history for ALL players in batches
589→    for (let i = 0; i < entries.length; i += BATCH_SIZE) {
590→      const batch = entries.slice(i, i + BATCH_SIZE);
591→      const accountIds = batch.map((e) => `'${sqlEscape(e.AccountId)}'`).join(", ");
592→      const deltaResp = await queryD1<{
593→        account_id: string;
594→        position: number;
595→        rating: number;
596→      }>({
597→        sql: `SELECT h.account_id, h.position, h.rating
598→              FROM player_history h
599→              WHERE h.season_id = ? AND h.account_id IN (${accountIds})
600→                AND h.snapshot_id <= ?
601→              ORDER BY h.snapshot_id DESC`,
602→        params: [seasonId, baselineSnapshotId],
603→      });
604→
605→      // Take only the latest row per account_id (results are ordered by snapshot_id DESC)
606→      const rows = deltaResp.result[0]?.results ?? [];
607→      for (const row of rows) {
608→        if (!deltaMap.has(row.account_id)) {
609→          deltaMap.set(row.account_id, {
610→            position: row.position,
611→            rating: row.rating,
612→          });
613→        }
614→      }
615→    }
616→
617→    // For players with no history entry at/before baseline, use their
618→    // current player_latest values (they've been unchanged since before baseline)
619→    for (const entry of entries) {
620→      if (!deltaMap.has(entry.AccountId)) {
621→        const prev = prevMap.get(entry.AccountId);
622→        if (prev) {
623→          deltaMap.set(entry.AccountId, {
624→            position: prev.position,
625→            rating: prev.rating,
626→          });
627→        }
628→      }
629→    }
630→  }
631→
632→  // 5a. UPSERT changed players to player_latest (updates all fields + baselines)
633→  if (changed.length > 0) {
634→    for (let i = 0; i < changed.length; i += BATCH_SIZE) {
635→      const batch = changed.slice(i, i + BATCH_SIZE);
636→      const values = batch
637→        .map((e) => {
638→          const delta = deltaMap.get(e.AccountId);
639→          const prevPos = delta ? delta.position : "NULL";
640→          const prevRat = delta ? delta.rating : "NULL";
641→          return `(${seasonId}, '${sqlEscape(e.AccountId)}', '${sqlEscape(e.Username)}', ${e.Position}, ${e.Rating}, '${sqlEscape(fetchedAt)}', ${prevPos}, ${prevRat})`;
642→        })
643→        .join(", ");
644→
645→      await queryD1({
646→        sql: `INSERT OR REPLACE INTO player_latest (season_id, account_id, username, position, rating, fetched_at, prev_position_24h, prev_rating_24h) VALUES ${values}`,
647→      });
648→    }
649→    log(`  Upserted ${changed.length} changed rows to player_latest`);
650→  }
651→
652→  // 5b. UPDATE baselines for unchanged players
653→  // These players already exist in player_latest but their prev_*_24h may be stale/NULL
654→  if (baselineSnapshotId) {
655→    const changedIds = new Set(changed.map((c) => c.AccountId));
656→    const unchanged = entries.filter((e) => !changedIds.has(e.AccountId));
657→    let updatedCount = 0;
658→    for (let i = 0; i < unchanged.length; i += BATCH_SIZE) {
659→      const batch = unchanged.slice(i, i + BATCH_SIZE);
660→      // Use CASE expressions to update multiple rows in one query
661→      const posCases: string[] = [];
662→      const ratCases: string[] = [];
663→      const ids: string[] = [];
664→      for (const e of batch) {
665→        const delta = deltaMap.get(e.AccountId);
666→        if (delta) {
667→          const escapedId = sqlEscape(e.AccountId);
668→          ids.push(`'${escapedId}'`);
669→          posCases.push(`WHEN '${escapedId}' THEN ${delta.position}`);
670→          ratCases.push(`WHEN '${escapedId}' THEN ${delta.rating}`);
671→        }
672→      }
673→      if (ids.length > 0) {
674→        await queryD1({
675→          sql: `UPDATE player_latest
676→                SET prev_position_24h = CASE account_id ${posCases.join(" ")} ELSE prev_position_24h END,
677→                    prev_rating_24h = CASE account_id ${ratCases.join(" ")} ELSE prev_rating_24h END
678→                WHERE season_id = ? AND account_id IN (${ids.join(", ")})`,
679→          params: [seasonId],
680→        });
681→        updatedCount += ids.length;
682→      }
683→    }
684→    if (updatedCount > 0) {
685→      log(`  Updated baselines for ${updatedCount} unchanged players`);
686→    }
687→  }
688→
689→  // 6. Delete delisted players
690→  const delistedIds: string[] = [];
691→  for (const accountId of prevMap.keys()) {
692→    if (!currentAccountIds.has(accountId)) {
693→      delistedIds.push(accountId);
694→    }
695→  }
696→  if (delistedIds.length > 0) {
697→    for (let i = 0; i < delistedIds.length; i += BATCH_SIZE) {
698→      const batch = delistedIds.slice(i, i + BATCH_SIZE);
699→      const ids = batch.map((id) => `'${sqlEscape(id)}'`).join(", ");
700→      await queryD1({
701→        sql: `DELETE FROM player_latest WHERE season_id = ? AND account_id IN (${ids})`,
702→        params: [seasonId],
703→      });
704→    }
705→    log(`  Deleted ${delistedIds.length} delisted players from player_latest`);
706→  }
707→
708→  log("Player tables synced.");
709→}
