854→      leaderboard.totalEntries,
855→      fetchedAt
856→    );
857→
858→    // 6. Compute metrics from memory
859→    await computeSnapshotMetricsFromMemory(snapshotId, entries);
860→
861→    // 7. Sync player tables
862→    await syncPlayerTables(snapshotId, seasonId, fetchedAt, entries);
863→
864→    // 8. Recompute per-player progress stats from season history
865→    await recomputePlayerProgress(seasonId);
866→
867→    // 9. Mark snapshot ready
868→    await markSnapshotReady(snapshotId);
869→
870→    // 10. Cleanup old seasons
871→    await cleanupOldSeasons();
872→
873→    log("=== Bazaar Leaderboard Fetch Complete ===");
874→  } finally {
875→    // Always refresh token for next run, even if main flow failed.
876→    // Access token expires in ~15 min but CI runs every 30 min,
877→    // so always refresh to keep the refresh token chain alive.
878→    await proactiveRefresh();
879→  }
880→}
