const activeProgressEntries = progressEntries.filter(([accountId]) =>
  activeAccountIds.has(accountId)
);
for (let i = 0; i < activeProgressEntries.length; i += BATCH_SIZE) {
  const batch = activeProgressEntries.slice(i, i + BATCH_SIZE);
